    /** Parsing invalid syntax should produce a tree with error nodes. */
    public function test_error_handling_invalid_syntax(): void
    {
        $config = \Tree\Sitter\Language\Pack\ProcessConfig::from_json(json_encode(['language' => 'javascript']));
        $this->expectNotToPerformAssertions();
        $result = TreeSitterLanguagePack::process('function function function @@@ %%%', $config);
    }

    /** Loading a nonexistent language should produce an error. */
    public function test_error_handling_unknown_language(): void
    {
        $this->expectException(\Exception::class);
        $config = \Tree\Sitter\Language\Pack\ProcessConfig::from_json(json_encode(['language' => 'nonexistent_xyz']));
        TreeSitterLanguagePack::process('', $config);
    }

    /** Process empty source code succeeds with zero metrics */
    public function test_error_process_empty_source(): void
    {
        $config = \Tree\Sitter\Language\Pack\ProcessConfig::from_json(json_encode(['language' => 'python']));
        $result = TreeSitterLanguagePack::process('', $config);

        $this->assertEquals(0, $result->getMetrics()->totalLines);
    }

    /** process() returns error with empty language name */
    public function test_parse_empty_language(): void
    {
        $this->expectException(\Exception::class);
        $config = \Tree\Sitter\Language\Pack\ProcessConfig::from_json(json_encode(['language' => '']));
        TreeSitterLanguagePack::process('x = 1', $config);
    }

    /** process() returns error when config language is unknown */
    public function test_process_unknown_language(): void
    {
        $this->expectException(\Exception::class);
        $config = \Tree\Sitter\Language\Pack\ProcessConfig::from_json(json_encode(['language' => 'nonexistent_xyz']));
        TreeSitterLanguagePack::process('x = 1', $config);
    }
}
